"""
add_week3a.py — MilaanAI Week 3 Part 1: fine-tune dataset + teacher labeling

Run from inside your milaan-ai folder:  python add_week3a.py
Overwrites cli.py (adds finetune-data / teacher-label / eval-cat commands).
"""
import os

FILES = {}

FILES['milaan/llm.py'] = '"""Dual-provider LLM layer (Anthropic / Gemini) — ported patterns from SahaayakAI:\n- provider switch via LLM_PROVIDER env var\n- Gemini model-name self-healing via ListModels (avoids 404s)\n- thinking tokens disabled, with automatic retry if thinkingConfig unsupported\n- minimum output-token budget enforced (no truncated JSON)\n- parse_json_block() strips markdown fences\n- every call logged to logs/telemetry.jsonl\n"""\n\nimport json\nimport os\nimport re\nimport time\nfrom pathlib import Path\n\nimport requests\nfrom dotenv import load_dotenv\n\nload_dotenv()\n\nTELEMETRY_PATH = Path("logs/telemetry.jsonl")\nMIN_OUTPUT_TOKENS = 1200\n\n\nclass LLMError(Exception):\n    pass\n\n\ndef _log(record: dict) -> None:\n    TELEMETRY_PATH.parent.mkdir(exist_ok=True)\n    record["ts"] = time.strftime("%Y-%m-%dT%H:%M:%S")\n    with TELEMETRY_PATH.open("a", encoding="utf-8") as f:\n        f.write(json.dumps(record, ensure_ascii=False) + "\\n")\n\n\ndef parse_json_block(text: str):\n    """Extract the first JSON object/array from text, tolerating ``` fences."""\n    if text is None:\n        raise LLMError("Empty LLM response")\n    cleaned = re.sub(r"```(?:json)?", "", text).strip().strip("`").strip()\n    # Fast path\n    try:\n        return json.loads(cleaned)\n    except json.JSONDecodeError:\n        pass\n    # Fallback: first {...} or [...] span\n    for opener, closer in (("{", "}"), ("[", "]")):\n        start = cleaned.find(opener)\n        end = cleaned.rfind(closer)\n        if start != -1 and end > start:\n            try:\n                return json.loads(cleaned[start : end + 1])\n            except json.JSONDecodeError:\n                continue\n    raise LLMError(f"Could not parse JSON from response: {cleaned[:300]}")\n\n\n# ---------------------------------------------------------------- Anthropic\ndef _anthropic_complete(prompt: str, system: str, max_tokens: int) -> str:\n    api_key = os.getenv("ANTHROPIC_API_KEY")\n    if not api_key:\n        raise LLMError("ANTHROPIC_API_KEY not set")\n    model = os.getenv("ANTHROPIC_MODEL", "claude-sonnet-4-6")\n    body = {\n        "model": model,\n        "max_tokens": max(max_tokens, MIN_OUTPUT_TOKENS),\n        "messages": [{"role": "user", "content": prompt}],\n    }\n    if system:\n        body["system"] = system\n    resp = requests.post(\n        "https://api.anthropic.com/v1/messages",\n        headers={\n            "x-api-key": api_key,\n            "anthropic-version": "2023-06-01",\n            "content-type": "application/json",\n        },\n        json=body,\n        timeout=120,\n    )\n    if resp.status_code != 200:\n        raise LLMError(f"Anthropic {resp.status_code}: {resp.text[:300]}")\n    data = resp.json()\n    return "".join(b.get("text", "") for b in data.get("content", []))\n\n\n# ------------------------------------------------------------------- Gemini\n_GEMINI_BASE = "https://generativelanguage.googleapis.com/v1beta"\n_resolved_gemini_model = None\n\n\ndef _gemini_list_models(api_key: str) -> list:\n    resp = requests.get(f"{_GEMINI_BASE}/models?key={api_key}", timeout=60)\n    if resp.status_code != 200:\n        raise LLMError(f"Gemini ListModels {resp.status_code}: {resp.text[:300]}")\n    models = resp.json().get("models", [])\n    return [\n        m["name"].split("/")[-1]\n        for m in models\n        if "generateContent" in m.get("supportedGenerationMethods", [])\n    ]\n\n\ndef _gemini_call(api_key: str, model: str, prompt: str, system: str,\n                 max_tokens: int, use_thinking_config: bool):\n    gen_cfg = {"maxOutputTokens": max(max_tokens, MIN_OUTPUT_TOKENS)}\n    if use_thinking_config:\n        gen_cfg["thinkingConfig"] = {"thinkingBudget": 0}\n    body = {\n        "contents": [{"role": "user", "parts": [{"text": prompt}]}],\n        "generationConfig": gen_cfg,\n    }\n    if system:\n        body["systemInstruction"] = {"parts": [{"text": system}]}\n    return requests.post(\n        f"{_GEMINI_BASE}/models/{model}:generateContent?key={api_key}",\n        json=body,\n        timeout=120,\n    )\n\n\ndef _gemini_complete(prompt: str, system: str, max_tokens: int) -> str:\n    global _resolved_gemini_model\n    api_key = os.getenv("GEMINI_API_KEY")\n    if not api_key:\n        raise LLMError("GEMINI_API_KEY not set")\n    model = _resolved_gemini_model or os.getenv("GEMINI_MODEL", "gemini-2.0-flash")\n\n    resp = _gemini_call(api_key, model, prompt, system, max_tokens, True)\n    if resp.status_code == 404:\n        # Self-heal: pick a working flash model from ListModels\n        available = _gemini_list_models(api_key)\n        flash = [m for m in available if "flash" in m and "exp" not in m]\n        if not (flash or available):\n            raise LLMError("No Gemini models support generateContent")\n        model = sorted(flash or available, reverse=True)[0]\n        _resolved_gemini_model = model\n        resp = _gemini_call(api_key, model, prompt, system, max_tokens, True)\n    if resp.status_code == 400 and "thinking" in resp.text.lower():\n        # Model doesn\'t accept thinkingConfig — retry without it\n        resp = _gemini_call(api_key, model, prompt, system, max_tokens, False)\n    if resp.status_code != 200:\n        raise LLMError(f"Gemini {resp.status_code}: {resp.text[:300]}")\n\n    data = resp.json()\n    try:\n        parts = data["candidates"][0]["content"]["parts"]\n        return "".join(p.get("text", "") for p in parts)\n    except (KeyError, IndexError):\n        raise LLMError(f"Unexpected Gemini response: {json.dumps(data)[:300]}")\n\n\n# -------------------------------------------------------------------- Public\ndef complete(prompt: str, system: str = "", max_tokens: int = 2000,\n             agent: str = "unknown") -> str:\n    provider = os.getenv("LLM_PROVIDER", "anthropic").lower()\n    t0 = time.time()\n    try:\n        if provider == "gemini":\n            text = _gemini_complete(prompt, system, max_tokens)\n        else:\n            text = _anthropic_complete(prompt, system, max_tokens)\n        _log({"agent": agent, "provider": provider, "ok": True,\n              "latency_s": round(time.time() - t0, 2),\n              "prompt_chars": len(prompt), "response_chars": len(text)})\n        return text\n    except Exception as e:\n        _log({"agent": agent, "provider": provider, "ok": False, "error": str(e)})\n        raise\n\n\ndef complete_json(prompt: str, system: str = "", max_tokens: int = 2000,\n                  agent: str = "unknown"):\n    return parse_json_block(complete(prompt, system, max_tokens, agent))\n'

FILES['milaan/finetune/__init__.py'] = ''

FILES['milaan/finetune/datagen.py'] = '"""Fine-tuning dataset generator: (narration, amount, direction) -> category.\n\nRicher than the reconciliation generator on purpose:\n- hundreds of combinatorial business/person names (so the model learns\n  patterns, not a fixed name list)\n- multiple narration templates per category, real-bank style\n- deterministic, split-hygienic (no narration string appears in two splits)\n\nOutput JSONL rows: {"text": "...", "category": "...", "narration": "...",\n                    "amount": float, "direction": "credit|debit"}\n`text` is the exact model input: "DIR=credit | AMT=45210 | NARR=UPI-..."\n"""\n\nimport json\nimport random\nfrom pathlib import Path\n\nSURNAMES = ["Sharma", "Patel", "Gupta", "Verma", "Iyer", "Khan", "Mehta",\n            "Reddy", "Joshi", "Bansal", "Nair", "Chawla", "Desai", "Kulkarni",\n            "Sinha", "Agarwal", "Mishra", "Yadav", "Rathi", "Bhatt", "Pillai",\n            "Ghosh", "Das", "Chopra", "Malhotra", "Saxena", "Trivedi", "Shah"]\nBIZ_TYPES = ["Traders", "Enterprises", "Textiles", "Electronics", "Distributors",\n             "Brothers", "Marketing", "Agencies", "Fabrics", "Steel", "Foods",\n             "Motors", "Ceramics", "Papers", "Polymers", "Sweets", "Packaging",\n             "Logistics", "Transport", "Stationers", "Printers", "Chemicals",\n             "Wholesale", "Suppliers", "Industries", "Exports", "Hardware"]\nFIRST_NAMES = ["Rahul", "Priya", "Amit", "Sneha", "Vikas", "Pooja", "Rohan",\n               "Neha", "Arjun", "Kavita", "Sanjay", "Divya", "Manish", "Anita",\n               "Deepak", "Ritu", "Suresh", "Meena", "Ajay", "Swati"]\nVPA_BANKS = ["okhdfcbank", "oksbi", "okicici", "ybl", "paytm", "ibl", "axl"]\nUTILITIES = ["MSEDCL", "TATA POWER", "ADANI ELEC", "BEST UNDERT", "AIRTEL",\n             "JIO FIBER", "MAHANAGAR GAS", "BWSSB WATER"]\nLENDERS = ["BAJAJ FINANCE", "HDFC BANK LOAN", "ICICI PL", "TATA CAPITAL",\n           "FULLERTON", "AXIS LOAN"]\nINSURERS = ["LIC OF INDIA", "HDFC ERGO", "ICICI LOMBARD", "STAR HEALTH",\n            "SBI LIFE", "MAX LIFE"]\n\n\ndef _vowel_drop(s):\n    return " ".join(w[0] + "".join(c for c in w[1:] if c not in "AEIOU")\n                    if len(w) > 4 else w for w in s.split())\n\n\ndef _mangle(name, rng):\n    up = name.upper()\n    return rng.choice([up, up, _vowel_drop(up), up[:rng.randint(8, 14)].strip()])\n\n\ndef _rrn(rng):\n    return str(rng.randint(10**11, 10**12 - 1))\n\n\ndef _utr(rng):\n    return f"N{rng.randint(10**8, 10**9 - 1)}"\n\n\ndef _biz(rng):\n    return f"{rng.choice(SURNAMES)} {rng.choice(BIZ_TYPES)}"\n\n\ndef _person(rng):\n    return f"{rng.choice(FIRST_NAMES)} {rng.choice(SURNAMES)}"\n\n\ndef _vpa(name, rng):\n    return f"{name.lower().split()[0][:8]}{rng.randint(1, 99)}@{rng.choice(VPA_BANKS)}"\n\n\n# --------------------------------------------------------------- per-category\ndef _sales_receipt(rng):\n    p = _biz(rng)\n    d = _mangle(p, rng)\n    mode = rng.choice(["UPI", "UPI", "IMPS", "NEFT", "RTGS", "CHQ"])\n    if mode == "UPI":\n        n = f"UPI-{d}-{_vpa(p, rng)}-{_rrn(rng)}-{rng.choice([\'PAYMENT\', \'INV PAYMENT\', \'COLLECT\'])}"\n    elif mode == "IMPS":\n        n = f"IMPS-{_rrn(rng)}-{d}"\n    elif mode == "NEFT":\n        n = f"NEFT CR-{_utr(rng)}-{d}"\n    elif mode == "RTGS":\n        n = f"RTGS-R{_utr(rng)[1:]}-{d}"\n    else:\n        n = f"CHQ DEP-{rng.randint(100000, 999999)}-{d}"\n    return n, float(rng.randint(1500, 250000)), "credit"\n\n\ndef _vendor_payment(rng):\n    p = _biz(rng)\n    d = _mangle(p, rng)\n    mode = rng.choice(["UPI", "NEFT", "IMPS", "RTGS"])\n    if mode == "UPI":\n        n = f"UPI-{d}-{_vpa(p, rng)}-{_rrn(rng)}-{rng.choice([\'PAYMENT\', \'PURCHASE\', \'BILL PMT\'])}"\n    elif mode == "NEFT":\n        n = f"NEFT DR-{_utr(rng)}-{d}"\n    elif mode == "IMPS":\n        n = f"IMPS-{_rrn(rng)}-{d}"\n    else:\n        n = f"RTGS-R{_utr(rng)[1:]}-{d}"\n    return n, float(rng.randint(800, 180000)), "debit"\n\n\ndef _salary(rng):\n    who = rng.choice(["STAFF PAYROLL", "SALARY " + rng.choice(\n        ["JUL", "AUG", "SEP", "OCT", "JAN", "FEB", "MAR"]),\n        _person(rng).upper() + " SAL"])\n    return (f"NEFT DR-{_utr(rng)}-{who}" if rng.random() < 0.7\n            else f"SAL-{who}-{_rrn(rng)[:8]}"), float(rng.randint(12000, 95000)), "debit"\n\n\ndef _rent(rng):\n    m = rng.choice(["JAN", "FEB", "MAR", "APR", "MAY", "JUN",\n                    "JUL", "AUG", "SEP", "OCT", "NOV", "DEC"])\n    forms = [f"NEFT DR-{_utr(rng)}-OFFICE RENT {m}",\n             f"RENT {m}-{_mangle(_person(rng), rng)}",\n             f"UPI-{_mangle(_person(rng), rng)}-{_rrn(rng)}-SHOP RENT"]\n    return rng.choice(forms), float(rng.randint(8000, 90000)), "debit"\n\n\ndef _bank_charges(rng):\n    forms = ["SMS CHARGES " + rng.choice(["MAR", "JUN", "SEP", "DEC"]) + " QTR",\n             "AMB CHRG INCL GST", "NEFT RETURN CHARGES GST",\n             "CHQ BOOK ISSUE CHG", "DEBIT CARD AMC", "MIN BAL CHARGES",\n             f"PROCESSING FEE-{_rrn(rng)[:6]}"]\n    return rng.choice(forms), float(rng.choice([29, 59, 118, 177, 236, 354, 590])), "debit"\n\n\ndef _gst_tds(rng):\n    forms = [f"GST PMT-{rng.randint(10**10, 10**11)}",\n             f"GSTN PAYMENT {_rrn(rng)[:8]}",\n             f"TDS PAYMENT CBDT-{rng.randint(10**7, 10**8)}",\n             "EPAYMENT-CBIC-GST", f"ADVANCE TAX-{rng.randint(10**6, 10**7)}"]\n    return rng.choice(forms), float(rng.randint(2000, 400000)), "debit"\n\n\ndef _loan_emi(rng):\n    l = rng.choice(LENDERS)\n    forms = [f"ACH D-{l}-EMI-{rng.randint(10**7, 10**8)}",\n             f"NACH-{l}-{_rrn(rng)[:8]}",\n             f"ECS-{l}-LOAN {rng.randint(10**5, 10**6)}"]\n    return rng.choice(forms), float(rng.randint(3500, 60000)), "debit"\n\n\ndef _utility(rng):\n    u = rng.choice(UTILITIES)\n    forms = [f"BILLPAY-{u}-{rng.choice([\'ELEC\', \'BILL\', \'RECHARGE\'])}-{rng.randint(10**6, 10**7)}",\n             f"BBPS-{u}-{_rrn(rng)[:8]}",\n             f"UPI-{u}-{u.lower().split()[0]}@{rng.choice(VPA_BANKS)}-{_rrn(rng)}-BILL"]\n    return rng.choice(forms), float(rng.randint(400, 18000)), "debit"\n\n\ndef _upi_p2p(rng):\n    p = _person(rng)\n    d = _mangle(p, rng)\n    direction = rng.choice(["credit", "debit"])\n    n = f"UPI-{d}-{_vpa(p, rng)}-{_rrn(rng)}-{rng.choice([\'\', \'SENT\', \'PAYMENT\', \'GPAY\', \'PHONEPE\'])}".rstrip("-")\n    return n, float(rng.randint(100, 25000)), direction\n\n\ndef _refund(rng):\n    src = rng.choice(["AMAZON", "FLIPKART", "MYNTRA", "SWIGGY", "ZOMATO",\n                      "IRCTC", _biz(rng).upper()])\n    forms = [f"REV-UPI-{_rrn(rng)}-{src}",\n             f"REFUND-{src}-{_rrn(rng)[:8]}",\n             f"UPI RET-{_rrn(rng)}-{src}",\n             f"IMPS REV-{_rrn(rng)}-{_mangle(src, rng) if \' \' in src else src}"]\n    return rng.choice(forms), float(rng.randint(99, 45000)), "credit"\n\n\ndef _interest(rng):\n    return rng.choice(["INT.PD. SB ACCOUNT", "SB INT CREDIT",\n                       f"FD INT-{rng.randint(10**6, 10**7)}",\n                       "INTEREST CAPITALISED"]), float(rng.randint(50, 9000)), "credit"\n\n\ndef _cash_dep(rng):\n    return rng.choice([f"CDM DEPOSIT-{rng.randint(10**5, 10**6)}",\n                       "CASH DEP BY SELF", f"CSH DEP-BRANCH-{rng.randint(100, 999)}"]), \\\n        float(rng.randint(1000, 200000) // 100 * 100), "credit"\n\n\ndef _cash_wdl(rng):\n    return rng.choice([f"ATM WDL-{rng.randint(10**5, 10**6)}-{rng.choice([\'MUMBAI\', \'PUNE\', \'THANE\', \'DELHI\'])}",\n                       "SELF CHQ WDL", f"NWD-{_rrn(rng)[:10]}"]), \\\n        float(rng.choice([500, 1000, 2000, 5000, 10000, 20000, 40000])), "debit"\n\n\ndef _insurance(rng):\n    i = rng.choice(INSURERS)\n    return rng.choice([f"ACH D-{i}-{rng.randint(10**7, 10**8)}",\n                       f"NACH-{i}-PREMIUM",\n                       f"BILLPAY-{i}-{_rrn(rng)[:8]}"]), \\\n        float(rng.randint(1500, 60000)), "debit"\n\n\ndef _other(rng):\n    forms = [f"BY TRANSFER-{_rrn(rng)[:8]}", "SWEEP TRF TO FD",\n             f"CLG-{rng.randint(10**5, 10**6)}", "DD ISSUE",\n             f"POS {rng.randint(10**5, 10**6)} {rng.choice([\'DMART\', \'RELIANCE RETAIL\', \'CROMA\'])}"]\n    return rng.choice(forms), float(rng.randint(200, 60000)), rng.choice(["credit", "debit"])\n\n\nMAKERS = {\n    "sales_receipt": _sales_receipt, "vendor_payment": _vendor_payment,\n    "salary": _salary, "rent": _rent, "bank_charges": _bank_charges,\n    "gst_tds_payment": _gst_tds, "loan_emi": _loan_emi,\n    "utility_bill": _utility, "upi_p2p": _upi_p2p, "refund": _refund,\n    "interest_credit": _interest, "cash_deposit": _cash_dep,\n    "cash_withdrawal": _cash_wdl, "insurance": _insurance, "other": _other,\n}\n\n# sampling weights: frequent categories appear more, like real statements\nWEIGHTS = {"sales_receipt": 22, "vendor_payment": 16, "upi_p2p": 10,\n           "salary": 6, "rent": 5, "bank_charges": 6, "gst_tds_payment": 6,\n           "loan_emi": 6, "utility_bill": 6, "refund": 5,\n           "interest_credit": 3, "cash_deposit": 3, "cash_withdrawal": 3,\n           "insurance": 4, "other": 3}\n\n\ndef to_text(narration, amount, direction):\n    return f"DIR={direction} | AMT={int(amount)} | NARR={narration}"\n\n\ndef generate_dataset(out_dir, n_train=8000, n_val=1000, n_test=1000, seed=42):\n    rng = random.Random(seed)\n    cats = [c for c, w in WEIGHTS.items() for _ in range(w)]\n    seen, rows = set(), []\n    target = n_train + n_val + n_test\n    while len(rows) < target:\n        cat = rng.choice(cats)\n        narration, amount, direction = MAKERS[cat](rng)\n        text = to_text(narration, amount, direction)\n        if text in seen:            # split hygiene: globally unique inputs\n            continue\n        seen.add(text)\n        rows.append({"text": text, "category": cat, "narration": narration,\n                     "amount": amount, "direction": direction})\n    rng.shuffle(rows)\n    splits = {"train": rows[:n_train],\n              "val": rows[n_train:n_train + n_val],\n              "test": rows[n_train + n_val:]}\n    out = Path(out_dir)\n    out.mkdir(parents=True, exist_ok=True)\n    for name, split in splits.items():\n        with (out / f"{name}.jsonl").open("w", encoding="utf-8") as f:\n            for r in split:\n                f.write(json.dumps(r, ensure_ascii=False) + "\\n")\n    return {k: len(v) for k, v in splits.items()}\n'

FILES['milaan/finetune/teacher.py'] = '"""Teacher labeling: frontier LLM predicts categories on test.jsonl.\n\nBatched (25 per call), resumable (skips already-predicted ids), telemetry\nlogged. Output: teacher_preds.jsonl rows {"text":..., "pred":...}.\nUses the dual-provider layer (LLM_PROVIDER=anthropic|gemini).\n"""\n\nimport json\nimport time\nfrom pathlib import Path\n\nfrom milaan.llm import complete_json\nfrom milaan.models import CATEGORIES\n\nBATCH = 25\n\nSYSTEM = (\n    "You classify Indian bank statement transactions into exactly one category. "\n    "Valid categories: " + ", ".join(CATEGORIES) + ". "\n    "Respond with JSON only — no prose, no markdown fences."\n)\n\nPROMPT = """Classify each transaction into exactly one category from:\n{cats}\n\nTransactions (id: text):\n{items}\n\nRespond with ONLY a JSON object mapping id to category, e.g.\n{{"0": "sales_receipt", "1": "rent"}}\n"""\n\n\ndef label_file(test_path: str, out_path: str, sleep_s: float = 2.0,\n               limit: int = 0):\n    rows = [json.loads(l) for l in open(test_path, encoding="utf-8")]\n    if limit:\n        rows = rows[:limit]\n    out = Path(out_path)\n    done = {}\n    if out.exists():\n        for l in out.open(encoding="utf-8"):\n            r = json.loads(l)\n            done[r["text"]] = r["pred"]\n    todo = [r for r in rows if r["text"] not in done]\n    print(f"{len(done)} already labeled, {len(todo)} to go")\n\n    with out.open("a", encoding="utf-8") as f:\n        for i in range(0, len(todo), BATCH):\n            batch = todo[i:i + BATCH]\n            items = "\\n".join(f"{j}: {r[\'text\']}" for j, r in enumerate(batch))\n            try:\n                preds = complete_json(\n                    PROMPT.format(cats=", ".join(CATEGORIES), items=items),\n                    system=SYSTEM, max_tokens=1500, agent="teacher")\n            except Exception as e:\n                print(f"batch {i // BATCH}: FAILED ({e}) — rerun to resume")\n                time.sleep(sleep_s * 3)\n                continue\n            for j, r in enumerate(batch):\n                pred = str(preds.get(str(j), "other")).strip()\n                if pred not in CATEGORIES:\n                    pred = "other"\n                f.write(json.dumps({"text": r["text"], "pred": pred},\n                                   ensure_ascii=False) + "\\n")\n            f.flush()\n            print(f"labeled {min(i + BATCH, len(todo))}/{len(todo)}")\n            time.sleep(sleep_s)\n    print(f"done -> {out}")\n\n\ndef evaluate_predictions(test_path: str, preds_path: str):\n    """Accuracy + per-category breakdown + confusion pairs, vs generator truth."""\n    truth = {r["text"]: r["category"]\n             for r in map(json.loads, open(test_path, encoding="utf-8"))}\n    preds = {r["text"]: r["pred"]\n             for r in map(json.loads, open(preds_path, encoding="utf-8"))}\n    common = [t for t in truth if t in preds]\n    if not common:\n        return {"n": 0}\n    correct = sum(1 for t in common if truth[t] == preds[t])\n    per_cat, confusion = {}, {}\n    for t in common:\n        c = truth[t]\n        per_cat.setdefault(c, [0, 0])\n        per_cat[c][1] += 1\n        if preds[t] == c:\n            per_cat[c][0] += 1\n        else:\n            key = (c, preds[t])\n            confusion[key] = confusion.get(key, 0) + 1\n    return {\n        "n": len(common),\n        "accuracy": round(correct / len(common), 4),\n        "per_category": {c: {"acc": round(a / b, 3), "n": b}\n                         for c, (a, b) in sorted(per_cat.items())},\n        "top_confusions": sorted(confusion.items(), key=lambda kv: -kv[1])[:8],\n    }\n'

FILES['cli.py'] = '"""MilaanAI CLI (Week 1).\n\n  python cli.py generate --months 10 --out data/synth --seed 42\n  python cli.py ingest --statement data/synth/m01/statement_hdfc.csv --ledger data/synth/m01/ledger.csv\n"""\n\nimport argparse\nimport json\nfrom pathlib import Path\n\nfrom milaan.generator.generate import generate_month, write_month\nfrom milaan.ingest.adapters import parse_statement, parse_ledger\nfrom milaan.ingest.integrity import check_balance\n\nFORMATS = ["hdfc", "icici", "sbi"]\n\n\ndef cmd_generate(args):\n    out_root = Path(args.out)\n    for i in range(args.months):\n        seed = args.seed + i\n        month = (i % 12) + 1\n        bank, ledger, gt = generate_month(seed, 2026, month)\n        fmt = FORMATS[i % 3]\n        mdir = out_root / f"m{i+1:02d}"\n        write_month(str(mdir), fmt, bank, ledger, gt)\n        n_disc = len(gt["unmatched_bank"]) + len(gt["unmatched_ledger"]) + sum(\n            1 for m in gt["matches"] if m["type"] != "CLEAN")\n        print(f"m{i+1:02d} [{fmt.upper():5}] bank={len(bank):3} "\n              f"ledger={len(ledger):3} planted_discrepancies={n_disc}")\n    print(f"\\nDone -> {out_root}  (last {args.holdout} months are HOLDOUT — "\n          "do not tune against them)")\n\n\ndef cmd_ingest(args):\n    txns, opening, fmt = parse_statement(args.statement)\n    report = check_balance(txns, opening)\n    print(f"Format detected : {fmt.upper()}")\n    print(f"Transactions    : {report[\'n_txns\']}")\n    print(f"Opening balance : {report[\'opening\']:,.2f}")\n    print(f"Closing balance : {report[\'closing\']:,.2f}")\n    print("Balance check   : PASSED")\n    if args.ledger:\n        entries = parse_ledger(args.ledger)\n        print(f"Ledger entries  : {len(entries)}")\n    print("\\nFirst 5 normalized txns:")\n    for t in txns[:5]:\n        print(f"  {t.txn_id} {t.date} {t.direction:6} {t.amount:>12,.2f}  "\n              f"{t.narration[:48]}")\n\n\n\n\ndef cmd_reconcile(args):\n    import json as _json\n    from milaan.match.engine import reconcile as _rec\n    from milaan.report.excel import write_report\n    txns, opening, fmt = parse_statement(args.statement)\n    check_balance(txns, opening)\n    entries = parse_ledger(args.ledger)\n    result = _rec(txns, entries)\n    out = Path(args.out)\n    out.parent.mkdir(parents=True, exist_ok=True)\n    n_bank = len(txns)\n    n_matched = sum(len(m["bank_ids"]) for m in result["matches"])\n    write_report(str(out), result, txns, entries,\n                 meta={"Statement": args.statement, "Format": fmt.upper()})\n    (out.with_suffix(".json")).write_text(\n        _json.dumps(result, indent=2, ensure_ascii=False), encoding="utf-8")\n    print(f"Matched {n_matched}/{n_bank} bank txns "\n          f"({n_matched/n_bank:.1%}) via {len(result[\'matches\'])} match groups")\n    print(f"Needs review: {len(result[\'unmatched_bank\'])} bank, "\n          f"{len(result[\'unmatched_ledger\'])} ledger")\n    print(f"Report -> {out}")\n\n\ndef cmd_eval(args):\n    from milaan.match.engine import reconcile as _rec\n    from milaan.evalx.harness import evaluate_dir\n    months = set(args.months.split(",")) if args.months else None\n    rows, overall = evaluate_dir(args.dir, _rec, parse_statement, parse_ledger,\n                                 months=months)\n    for r in rows:\n        print(f"{r[\'month\']}: P={r[\'precision\']:.3f} R={r[\'recall\']:.3f} "\n              f"F1={r[\'f1\']:.3f} dupes {r[\'dupes_caught\']}/{r[\'dupes_truth\']}")\n        for w in r["wrong_pairs"]:\n            print(f"   WRONG {w}")\n        for w in r["missed_pairs"]:\n            print(f"   MISSED {w}")\n    print(f"OVERALL: P={overall[\'precision\']:.4f} R={overall[\'recall\']:.4f} "\n          f"F1={overall[\'f1\']:.4f}")\n\n\n\ndef cmd_ftdata(args):\n    from milaan.finetune.datagen import generate_dataset\n    counts = generate_dataset(args.out, n_train=args.train, n_val=args.val,\n                              n_test=args.test, seed=args.seed)\n    print(f"dataset -> {args.out}  {counts}")\n\n\ndef cmd_teacher(args):\n    from milaan.finetune.teacher import label_file\n    label_file(args.test, args.out, limit=args.limit)\n\n\ndef cmd_evalcat(args):\n    import json as _json\n    from milaan.finetune.teacher import evaluate_predictions\n    rep = evaluate_predictions(args.test, args.preds)\n    print(_json.dumps(rep, indent=2))\n\ndef main():\n    p = argparse.ArgumentParser(prog="milaan")\n    sub = p.add_subparsers(dest="cmd", required=True)\n\n    g = sub.add_parser("generate")\n    g.add_argument("--months", type=int, default=10)\n    g.add_argument("--out", default="data/synth")\n    g.add_argument("--seed", type=int, default=42)\n    g.add_argument("--holdout", type=int, default=3)\n    g.set_defaults(func=cmd_generate)\n\n    i = sub.add_parser("ingest")\n    i.add_argument("--statement", required=True)\n    i.add_argument("--ledger")\n    i.set_defaults(func=cmd_ingest)\n\n    r = sub.add_parser("reconcile")\n    r.add_argument("--statement", required=True)\n    r.add_argument("--ledger", required=True)\n    r.add_argument("--out", default="outputs/reconciliation_report.xlsx")\n    r.set_defaults(func=cmd_reconcile)\n\n    e = sub.add_parser("eval")\n    e.add_argument("--dir", default="data/synth")\n    e.add_argument("--months", help="comma-separated, e.g. m08,m09,m10")\n    e.set_defaults(func=cmd_eval)\n\n    fd = sub.add_parser("finetune-data")\n    fd.add_argument("--out", default="data/finetune")\n    fd.add_argument("--train", type=int, default=8000)\n    fd.add_argument("--val", type=int, default=1000)\n    fd.add_argument("--test", type=int, default=1000)\n    fd.add_argument("--seed", type=int, default=42)\n    fd.set_defaults(func=cmd_ftdata)\n\n    tl = sub.add_parser("teacher-label")\n    tl.add_argument("--test", default="data/finetune/test.jsonl")\n    tl.add_argument("--out", default="data/finetune/teacher_preds.jsonl")\n    tl.add_argument("--limit", type=int, default=500)\n    tl.set_defaults(func=cmd_teacher)\n\n    ec = sub.add_parser("eval-cat")\n    ec.add_argument("--test", default="data/finetune/test.jsonl")\n    ec.add_argument("--preds", required=True)\n    ec.set_defaults(func=cmd_evalcat)\n\n    args = p.parse_args()\n    args.func(args)\n\n\nif __name__ == "__main__":\n    main()\n'

FILES['tests/test_week3a.py'] = '"""Week 3a tests — fine-tune dataset + teacher eval logic. No keys."""\n\nimport json\n\nfrom milaan.finetune.datagen import generate_dataset, MAKERS, to_text\nfrom milaan.finetune.teacher import evaluate_predictions\nfrom milaan.models import CATEGORIES\n\nimport random\n\n\ndef test_all_categories_have_makers():\n    assert set(MAKERS.keys()) == set(CATEGORIES)\n\n\ndef test_dataset_splits_and_hygiene(tmp_path):\n    counts = generate_dataset(str(tmp_path), n_train=800, n_val=100,\n                              n_test=100, seed=7)\n    assert counts == {"train": 800, "val": 100, "test": 100}\n    seen = set()\n    for split in ("train", "val", "test"):\n        for l in open(tmp_path / f"{split}.jsonl", encoding="utf-8"):\n            r = json.loads(l)\n            assert r["text"] not in seen, "leakage between splits"\n            seen.add(r["text"])\n            assert r["category"] in CATEGORIES\n            assert r["direction"] in ("credit", "debit")\n\n\ndef test_dataset_deterministic(tmp_path):\n    a = tmp_path / "a"; b = tmp_path / "b"\n    generate_dataset(str(a), 200, 50, 50, seed=3)\n    generate_dataset(str(b), 200, 50, 50, seed=3)\n    assert (a / "train.jsonl").read_text() == (b / "train.jsonl").read_text()\n\n\ndef test_makers_direction_sanity():\n    rng = random.Random(1)\n    for _ in range(50):\n        assert MAKERS["sales_receipt"](rng)[2] == "credit"\n        assert MAKERS["vendor_payment"](rng)[2] == "debit"\n        assert MAKERS["refund"](rng)[2] == "credit"\n        assert MAKERS["cash_withdrawal"](rng)[2] == "debit"\n\n\ndef test_evaluate_predictions(tmp_path):\n    test_f = tmp_path / "test.jsonl"; pred_f = tmp_path / "preds.jsonl"\n    rows = [{"text": to_text(f"N{i}", 100, "debit"), "category": "rent",\n             "narration": f"N{i}", "amount": 100, "direction": "debit"}\n            for i in range(10)]\n    test_f.write_text("\\n".join(json.dumps(r) for r in rows))\n    preds = [{"text": r["text"], "pred": "rent" if i < 8 else "salary"}\n             for i, r in enumerate(rows)]\n    pred_f.write_text("\\n".join(json.dumps(p) for p in preds))\n    rep = evaluate_predictions(str(test_f), str(pred_f))\n    assert rep["n"] == 10 and rep["accuracy"] == 0.8\n    assert rep["top_confusions"][0][0] == ("rent", "salary")\n'


ENV_EXAMPLE = """LLM_PROVIDER=gemini
GEMINI_API_KEY=
GEMINI_MODEL=gemini-2.0-flash
ANTHROPIC_API_KEY=
ANTHROPIC_MODEL=claude-sonnet-4-6
"""


def main():
    for rel, content in FILES.items():
        path = os.path.join(os.getcwd(), rel.replace("/", os.sep))
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
        with open(path, "w", encoding="utf-8", newline="\n") as fh:
            fh.write(content)
        print(f"  wrote: {rel}")
    if not os.path.exists(".env.example") or ".env.example":
        with open(".env.example", "w", encoding="utf-8") as fh:
            fh.write(ENV_EXAMPLE)
        print("  wrote: .env.example")
    print("""
Week 3 Part 1 installed.
NEXT STEPS
  1. pip install requests python-dotenv
  2. python -m pytest                              (expect 27 passed)
  3. python cli.py finetune-data --out data/finetune
  4. copy .env.example .env    then paste your GEMINI_API_KEY into .env
  5. python cli.py teacher-label --limit 500       (~20 batches, a few minutes; resumable)
  6. python cli.py eval-cat --preds data/finetune/teacher_preds.jsonl
Step 6 prints the TEACHER's accuracy — the number your fine-tuned model must beat.
""")


if __name__ == "__main__":
    main()
